import React, { useState } from "react";
import axios from "axios";
import "./forgotpassword.css";

const ForgotPasswordPage = () => {
  const [userEmail, setUserEmail] = useState("");
  const [otp, setOtp] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [step, setStep] = useState("email"); // email -> otp -> reset-password -> success

  const handlePasswordResetRequest = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!userEmail.trim()) {
      setError("Email is required.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/forgot-password", { email: userEmail });
      if (response.data.success) {
        setMessage("OTP sent to your email. Enter it below.");
        setStep("otp");
      } else {
        setError(response.data.message);
      }
    } catch (err) {
      setError("Error sending OTP. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!otp.trim()) {
      setError("OTP is required.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", { email: userEmail, otp });
      if (response.data.success) {
        setMessage("OTP Verified! You can now reset your password.");
        setStep("reset-password");
      } else {
        setError(response.data.message);
      }
    } catch (err) {
      setError("Error verifying OTP. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePasswordReset = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (newPassword !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/reset-password", { email: userEmail, newPassword });
      if (response.data.success) {
        setMessage("Password reset successful! You can now login.");
        setStep("success");
      } else {
        setError(response.data.message);
      }
    } catch (err) {
      setError("Error resetting password. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="forgot-password-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      {step === "email" && (
        <form onSubmit={handlePasswordResetRequest} className="forgot-password-form">
          <h2>Forgot Password</h2>
          <p>Enter your registered email to receive an OTP</p>
          <input type="email" placeholder="College Mail ID" value={userEmail} onChange={(e) => setUserEmail(e.target.value)} required disabled={isSubmitting} />
          <button type="submit" disabled={isSubmitting}>{isSubmitting ? "Sending..." : "Send OTP"}</button>
        </form>
      )}

      {step === "otp" && (
        <form onSubmit={handleOtpSubmit} className="forgot-password-form">
          <h2>Verify OTP</h2>
          <p>Enter the 6-digit OTP sent to your email</p>
          <input type="text" placeholder="Enter OTP" value={otp} onChange={(e) => setOtp(e.target.value)} maxLength="6" required disabled={isSubmitting} />
          <button type="submit" disabled={isSubmitting}>{isSubmitting ? "Verifying..." : "Verify OTP"}</button>
        </form>
      )}

      {step === "reset-password" && (
        <form onSubmit={handlePasswordReset} className="forgot-password-form">
          <h2>Reset Password</h2>
          <p>Enter your new password</p>
          <input type="password" placeholder="New Password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} required disabled={isSubmitting} />
          <input type="password" placeholder="Confirm Password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} required disabled={isSubmitting} />
          <button type="submit" disabled={isSubmitting}>{isSubmitting ? "Resetting..." : "Reset Password"}</button>
        </form>
      )}

      {step === "success" && (
        <div className="success-message">
          <h2>Password Reset Successfully!</h2>
          <p>You can now login with your new password.</p>
        </div>
      )}

      {message && <p className="success-message">{message}</p>}
      {error && <p className="error-message">{error}</p>}

      <div className="back-to-login">
        <a href="#" onClick={() => window.location.reload()}>Back to Login</a>
      </div>
    </div>
  );
};

export default ForgotPasswordPage;
